from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Extract main subject (typically airport)
    main_subject = next(iter(subject_map.keys()), "")
    if not main_subject:
        return ""

    # Group predicates by relevance for sentence construction
    city_served = None
    location = None
    country = None
    capital = None
    other_info = []

    # First pass: extract key relationships
    for predicate, obj in subject_map[main_subject]:
        if predicate == "cityServed":
            city_served = obj
        elif predicate == "location":
            location = obj
        elif predicate == "country":
            country = obj
        elif predicate == "capital":
            capital = obj
        elif predicate == "demonym":
            other_info.append(f"the people are called {obj}")
        elif predicate == "language" or predicate == "officialLanguage":
            other_info.append(f"{obj} is spoken")
        elif predicate == "leader":
            other_info.append(f"led by {obj}")
        elif predicate == "operatingOrganisation":
            other_info.append(f"operated by {obj}")
        elif predicate == "owner":
            other_info.append(f"owned by {obj}")
        elif predicate == "elevationAboveTheSeaLevel":
            other_info.append(f"elevated at {obj} metres above sea level")
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            other_info.append(f"elevated at {obj} feet above sea level")
        elif predicate == "runwayLength":
            other_info.append(f"has a runway length of {obj} metres")
        elif predicate == "1stRunwayLengthFeet":
            other_info.append(f"has a first runway of {obj} feet")
        elif predicate == "3rdRunwayLengthFeet":
            other_info.append(f"has a third runway of {obj} feet")
        elif predicate == "1stRunwayNumber":
            other_info.append(f"has a first runway numbered {obj}")
        elif predicate == "1stRunwaySurfaceType":
            other_info.append(f"has a first runway with surface type {obj}")
        elif predicate == "icaoLocationIdentifier":
            other_info.append(f"ICAO identifier: {obj}")
        elif predicate == "iataLocationIdentifier":
            other_info.append(f"IATA identifier: {obj}")
        elif predicate == "locationIdentifier":
            other_info.append(f"location identifier: {obj}")
        elif predicate == "nativeName":
            other_info.append(f"native name: {obj}")
        elif predicate == "leaderParty":
            other_info.append(f"leader's party: {obj}")
        elif predicate == "isPartOf":
            other_info.append(f"is part of {obj}")
        elif predicate == "jurisdiction":
            other_info.append(f"under jurisdiction of {obj}")
        elif predicate == "largestCity":
            other_info.append(f"its largest city is {obj}")
        elif predicate == "mayor":
            other_info.append(f"mayor is {obj}")
        elif predicate == "runwaySurfaceType":
            other_info.append(f"runway surface: {obj}")
        else:
            # Fallback for any unknown predicate
            other_info.append(f"has {predicate.replace('_', ' ')} of {obj}")

    # Build sentence logically: Airport -> City -> Country -> Other
    sentence = main_subject
    if city_served:
        sentence += f" serves the city of {city_served}"
    if location and location != city_served:
        sentence += f", located in {location}"
    if country:
        sentence += f", in {country}"
    if capital:
        sentence += f", with capital {capital}"

    # Add other information with proper punctuation
    if other_info:
        if sentence:
            sentence += "; "
        sentence += "; ".join(other_info)

    return sentence + "."

